1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	  firstInsurance?: boolean;
13	  followUp?: boolean;
14	}
15	
16	const PROCESSING_FEE = 5;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const CURSE_SURCHARGE_RATE = 0.5;
31	
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	
35	function tallyBy<T>(items: T[], keyOf: (item: T) => string): Map<string, number> {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    const key = keyOf(item);
39	    counts.set(key, (counts.get(key) ?? 0) + 1);
40	  }
41	  return counts;
42	}
43	
44	function countByType(items: QuoteItem[]): Map<string, number> {
45	  return tallyBy(items, (item) => item.type);
46	}
47	
48	function priceGroup(type: string, count: number): number {
49	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
50	}
51	
52	function surchargeFor(
53	  items: QuoteItem[],
54	  applies: (item: QuoteItem) => boolean,
55	  rate: number,
56	): number {
57	  let surcharge = 0;
58	  for (const item of items) {
59	    if (applies(item)) {
60	      surcharge += BASE_PREMIUMS[item.type] * rate;
61	    }
62	  }
63	  return surcharge;
64	}
65	
66	function curseSurchargeFor(items: QuoteItem[]): number {
67	  return surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
68	}
69	
70	function highEnchantmentSurchargeFor(items: QuoteItem[]): number {
71	  return surchargeFor(
72	    items,
73	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
74	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
75	  );
76	}
77	
78	function policyBasePremiumFor(items: QuoteItem[]): number {
79	  const countsByType = countByType(items);
80	
81	  let basePremium = 0;
82	  for (const [type, count] of countsByType) {
83	    basePremium += priceGroup(type, count);
84	  }
85	  return basePremium;
86	}
87	
88	function itemSurchargesFor(items: QuoteItem[]): number {
89	  return curseSurchargeFor(items) + highEnchantmentSurchargeFor(items);
90	}
91	
92	const LOYALTY_YEARS_THRESHOLD = 2;
93	
94	// Signed rates of the policy base premium: discounts are negative, surcharges positive.
95	const LOYALTY_DISCOUNT_RATE = -0.2;
96	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
97	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
98	
99	function policyWideModifiersFor(input: QuoteInput, policyBasePremium: number): number {
100	  const activeRates = [
101	    { active: input.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: LOYALTY_DISCOUNT_RATE },
102	    { active: input.firstInsurance, rate: FIRST_INSURANCE_SURCHARGE_RATE },
103	    { active: input.followUp, rate: FOLLOW_UP_DISCOUNT_RATE },
104	  ];
105	
106	  let total = 0;
107	  for (const { active, rate } of activeRates) {
108	    if (active) {
109	      total += policyBasePremium * rate;
110	    }
111	  }
112	  return total;
113	}
114	
115	export function quote(input: QuoteInput): number {
116	  const policyBasePremium = policyBasePremiumFor(input.items);
117	  const premiumWithSurcharges = policyBasePremium + itemSurchargesFor(input.items);
118	  const policyWideModifiers = policyWideModifiersFor(input, policyBasePremium);
119	  return Math.ceil(premiumWithSurcharges + policyWideModifiers + PROCESSING_FEE);
120	}
