122	interface ClaimPolicy {
123	  items: QuoteItem[];
124	}
125	
126	interface ClaimDamage {
127	  itemType: string;
128	  amount: number;
129	}
130	
131	interface ClaimIncident {
132	  cause: string;
133	  damages: ClaimDamage[];
134	}
135	
136	interface ClaimResult {
137	  payout: number;
138	  remainingCap: number;
139	}
140	
141	const DEDUCTIBLE = 100;
142	const CAP_MULTIPLIER = 2;
143	
144	const INSURANCE_VALUES: Record<string, number> = {
145	  sword: 1000,
146	  amulet: 600,
147	  staff: 800,
148	  potion: 400,
149	  rune: 250,
150	  moonstone: 250,
151	};
152	
153	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
154	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
155	
156	function isHighlyEnchanted(item: QuoteItem | undefined): boolean {
157	  return (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
158	}
159	
160	function insuredItemFor(damage: ClaimDamage, policy: ClaimPolicy): QuoteItem | undefined {
161	  return policy.items.find((item) => item.type === damage.itemType);
162	}
163	
164	function validateIncident(incident: ClaimIncident, policy: ClaimPolicy): void {
165	  for (const damage of incident.damages) {
166	    if (damage.amount < 0) {
167	      throw new Error(`Damage amount for "${damage.itemType}" cannot be negative`);
168	    }
169	  }
170	
171	  const insuredCounts = countByType(policy.items);
172	  const damageCounts = tallyBy(incident.damages, (damage) => damage.itemType);
173	
174	  for (const [itemType, damageCount] of damageCounts) {
175	    if (damageCount > (insuredCounts.get(itemType) ?? 0)) {
176	      throw new Error(`Damage references more "${itemType}" items than the policy insures`);
177	    }
178	  }
179	}
180	
181	function reimbursementFor(damage: ClaimDamage, policy: ClaimPolicy): number {
182	  const insuredItem = insuredItemFor(damage, policy);
183	  if (isHighlyEnchanted(insuredItem)) {
184	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
185	  }
186	  return damage.amount;
187	}
188	
189	function payoutFor(incident: ClaimIncident, policy: ClaimPolicy): number {
190	  let payout = 0;
191	  for (const damage of incident.damages) {
192	    payout += reimbursementFor(damage, policy) - DEDUCTIBLE;
193	  }
194	  return payout;
195	}
196	
197	function capFor(policy: ClaimPolicy): number {
198	  let insuranceTotal = 0;
199	  for (const item of policy.items) {
200	    insuranceTotal += INSURANCE_VALUES[item.type];
201	  }
202	  return CAP_MULTIPLIER * insuranceTotal;
203	}
204	
205	export function claim(
206	  policy: ClaimPolicy,
207	  incident: ClaimIncident,
208	  remainingCap?: number,
209	): ClaimResult {
210	  validateIncident(incident, policy);
211	  const rawPayout = payoutFor(incident, policy);
212	  const availableCap = remainingCap ?? capFor(policy);
213	  const payout = Math.min(rawPayout, availableCap);
214	  return { payout, remainingCap: availableCap - payout };
215	}
